import React, { useContext } from "react";
import { Routes, Route } from "react-router-dom";
import WatchList from "./WatchList";
import Summary from "./Summary";
import Orders from "./Orders";
import Holdings from "./Holdings";
import BuyActionWindow from "./BuyActionWindow";
import { GeneralContext } from "./GeneralContext";

const Dashboard = () => {
  const { isBuyWindowOpen } = useContext(GeneralContext);

  return (
    <div className="main-layout">
      {/* 1. Global Header remains anchored at the very top */}
      <Topbar />

      {/* 2. Workspace splitter container (Watchlist left, contents right) */}
      <div className="dashboard-container">
        <WatchList />

        <div className="content">
          <Routes>
            <Route path="/" element={<Summary />} />
            <Route path="/orders" element={<Orders />} />
            <Route path="/holdings" element={<Holdings />} />
          </Routes>
        </div>
      </div>

      {/* Interactive execution popup modal window */}
      {isBuyWindowOpen && <BuyActionWindow mode="BUY" />}
    </div>
  );
};

export default Dashboard;
